SELECT SUM(total) AS total_immigrants
FROM immigration_records
WHERE country_id = 0 AND year = 2007;

SELECT total
FROM immigration_records
WHERE country_id = 1 AND year = 2007;

SELECT AVG(median_age) AS average_median_age
FROM immigration_records
WHERE year = 2007 AND country_id = 1;

SELECT SUM(immigrants_count) AS total_employment_immigrants
FROM immigration_data
WHERE category_id = 1 AND country_id = 1;

SELECT MIN(total) AS min_total_immigrants
FROM immigration_records
WHERE year = 2023;
